-- Migration 156: strip leftover prod sections from short_description.
--
-- For every CompTIA/AWS course where prod's short_description still
-- contains an <hN> section that should already have been moved out
-- (Exam Voucher, Certification Exam at Pearson Vue, AWS Skill Builder),
-- REPLACE() the exact byte sequence using UNHEX() hex literals so MySQL
-- string escape interpretation can't drop the match the way it did for
-- migrations 151 and 152.
--
-- Source of truth: live scrape of tertiarycourses.com.sg at generation
-- time. Re-running on rows where the section has already been stripped
-- is a safe REPLACE no-op.

-- TGS-2024048318 (entity_id=25): pearson-vue
UPDATE catalog_product_entity_text SET value = REPLACE(value, UNHEX(''), '') WHERE entity_id = 25 AND attribute_id = 73;

-- TGS-2024049214 (entity_id=149): pearson-vue
UPDATE catalog_product_entity_text SET value = REPLACE(value, UNHEX(''), '') WHERE entity_id = 149 AND attribute_id = 73;

